class Solution {
    public int minChanges(int n, int k) {
        if (k > n) {
            return -1;
        }
        int count = 0;
        for (int i = 0; i < 32; i++) {
            int nBit = (n >> i) & 1;
            int kBit = (k >> i) & 1;
            if (kBit == 1 && nBit == 0) {
                return -1;
            } else if (nBit == 1 && kBit == 0) {
                count++;
            }
        }
        return count;
    }
}

